    20→
    21→import org.apache.flink.annotation.PublicEvolving;
    22→import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
    23→
    24→/**
    25→ * A {@link Trigger} that fires when the market close time is reached (watermark passes the end of
    26→ * the trading session window). This trigger is designed for use with {@link
    27→ * org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow} to fire trading
    28→ * session aggregations at market close.
    29→ *
    30→ * <p>The trigger supports early firing via overridable {@link #onElement(Object, long, TimeWindow,
    31→ * TriggerContext)} to handle circuit breaker halts or other market events.
    32→ *
    33→ * @see org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow
    34→ */
    35→@PublicEvolving
    36→public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    37→    private static final long serialVersionUID = 1L;
    38→
    39→    private PricingSessionTrigger() {}
    40→
    41→    @Override
    42→    public TriggerResult onElement(
    43→            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
    44→            throws Exception {
    45→        if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
    46→            // if the watermark is already past the window fire immediately
    47→            return TriggerResult.FIRE;
    48→        } else {
    49→            ctx.registerEventTimeTimer(window.maxTimestamp());
    50→            return TriggerResult.CONTINUE;
    51→        }
    52→    }
    53→
    54→    @Override
    55→    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
    56→        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    57→    }
    58→
    59→    @Override
    60→    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
    61→            throws Exception {
    62→        return TriggerResult.CONTINUE;
    63→    }
    64→
    65→    @Override
    66→    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
    67→        ctx.deleteEventTimeTimer(window.maxTimestamp());
    68→    }
    69→
    70→    @Override
    71→    public boolean canMerge() {
    72→        return true;
    73→    }
    74→
    75→    @Override
    76→    public void onMerge(TimeWindow window, OnMergeContext ctx) {
    77→        // only register a timer if the watermark is not yet past the end of the merged window
    78→        // this is in line with the logic in onElement(). If the watermark is past the end of
    79→        // the window onElement() will fire and setting a timer here would fire the window twice.
    80→        long windowMaxTimestamp = window.maxTimestamp();
    81→        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
    82→            ctx.registerEventTimeTimer(windowMaxTimestamp);
    83→        }
    84→    }
    85→
    86→    @Override
    87→    public String toString() {
    88→        return "PricingSessionTrigger()";
    89→    }
    90→
    91→    /**
    92→     * Creates a pricing session trigger that fires when the watermark passes the end of the
    93→     * trading session window.
    94→     *
    95→     * <p>Once the trigger fires all elements are discarded. Elements that arrive late immediately
    96→     * trigger window evaluation with just this one element.
    97→     *
    98→     * @return A new PricingSessionTrigger instance
    99→     */
   100→    public static PricingSessionTrigger create() {
   101→        return new PricingSessionTrigger();
   102→    }
   103→}
